#include <stdio.h>
#include <string.h>
int main() {
    int T, N, K, Answer, Ai;
    char Operator[10];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &K, &Answer);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        scanf("%s", Operator);
        for (int i = 0; i < K; i++) {
            for (int j = 0; j < N; j++) {
                if (strcmp(Operator, "XOR") == 0) {
                    Answer ^= A[j];
                } else if (strcmp(Operator, "AND") == 0) {
                    Answer &= A[j];
                } else if (strcmp(Operator, "OR") == 0) {
                    Answer |= A[j];
                }
            }
        }
        printf("%d\n", Answer);
    }
    return 0;
}

